import { useState } from "react";
import { logoutUser } from "../services/auth";
import { useNavigate } from "react-router-dom";

export default function AgentDashboard() {
  const [searchQuery, setSearchQuery] = useState("");
  const navigate = useNavigate();

  const handleLogout = async () => {
    await logoutUser();
    navigate("/login");
  };

  // We will replace this with real Firebase data in the next step
  const mockPolicies = [
    { id: 1, title: "Refund Policy", content: "Do not guarantee outcomes or promise refunds without Team Lead approval." },
    { id: 2, title: "Shipping Delays", content: "Standard shipping takes 3 to 5 business days. Expedited is 1 to 2 days." },
    { id: 3, title: "Account Verification", content: "Always verify the caller's email and phone number before discussing account details." }
  ];

  // Simple filter for our mock data
  const filteredPolicies = mockPolicies.filter(policy => 
    policy.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
    policy.content.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-white shadow-sm px-8 py-4 flex justify-between items-center">
        <h1 className="text-xl font-bold text-gray-800">CSR Portal</h1>
        <button 
          onClick={handleLogout}
          className="text-gray-600 hover:text-red-600 font-medium"
        >
          Sign Out
        </button>
      </nav>

      <div className="max-w-4xl mx-auto p-8">
        <h2 className="text-3xl font-bold text-gray-800 mb-8">Knowledge Base</h2>

        <div className="mb-8">
          <input
            type="text"
            placeholder="Search policies..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full p-4 rounded-lg shadow-sm border border-gray-200 focus:outline-none focus:ring-2 focus:ring-blue-500 text-lg"
          />
        </div>

        <div className="space-y-4">
          {filteredPolicies.map(policy => (
            <div key={policy.id} className="bg-white p-6 rounded-lg shadow-sm border border-gray-100">
              <h3 className="text-xl font-semibold text-gray-800 mb-2">{policy.title}</h3>
              <p className="text-gray-600">{policy.content}</p>
            </div>
          ))}

          {filteredPolicies.length === 0 && (
            <p className="text-gray-500 text-center py-8">No policies found matching your search.</p>
          )}
        </div>
      </div>
    </div>
  );
}
